from functools import wraps
from flask import Flask, session, redirect, url_for, request, render_template_string

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

users = {
    'admin': 'admin123',
    'user': 'user123'
}

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            session['next'] = request.url
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

def get_redirect_target():
    for target in request.values.get('next'), session.get('next'):
        if target:
            return target
    return url_for('index')

def redirect_to_next():
    target = get_redirect_target()
    if 'next' in session:
        session.pop('next')
    return redirect(target)

@app.route('/')
def index():
    if 'username' in session:
        return f'<h1>Welcome {session["username"]}!</h1><a href="/logout">Logout</a><br><a href="/dashboard">Dashboard</a><br><a href="/profile">Profile</a>'
    return '<h1>Home Page</h1><a href="/login">Login</a>'

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if username in users and users[username] == password:
            session['username'] = username
            return redirect_to_next()
        else:
            return render_template_string('''
                <h2>Login Failed</h2>
                <p>Invalid credentials</p>
                <a href="/login">Try again</a>
            ''')
    
    next_url = request.args.get('next', '')
    return render_template_string('''
        <h2>Login</h2>
        <form method="post">
            <input type="text" name="username" placeholder="Username" required><br>
            <input type="password" name="password" placeholder="Password" required><br>
            <input type="hidden" name="next" value="{{ next_url }}">
            <button type="submit">Login</button>
        </form>
        <p>Try: admin/admin123 or user/user123</p>
    ''', next_url=next_url)

@app.route('/logout')
def logout():
    session.pop('username', None)
    session.pop('next', None)
    return redirect(url_for('index'))

@app.route('/dashboard')
@login_required
def dashboard():
    return f'<h1>Dashboard</h1><p>Welcome {session["username"]}!</p><a href="/">Home</a><br><a href="/logout">Logout</a>'

@app.route('/profile')
@login_required
def profile():
    return f'<h1>Profile</h1><p>User: {session["username"]}</p><a href="/">Home</a><br><a href="/logout">Logout</a>'

if __name__ == '__main__':
    app.run(debug=True)